function ModelPay:CreateOrderReq(httpUrl,refId,uniqueId)
	self._reqCreateOrderUniqueId = uniqueId

	local pb = LProtoHelper.CreateProto(LProtoIds.CreateOrderReq)
	pb.httpUrl = httpUrl
	pb.refId = refId
	pb.uniqueId = uniqueId
	SendMessage(pb,LProtoIds.CreateOrderReq)
end

function ModelPay:IsCreateOrderReqing(uniqueId)
	return self._reqCreateOrderUniqueId == uniqueId
end

function ModelPay:OnCreateOrderResp(pb)
	local url = pb.httpUrl
	if string.isempty(url) and not string.isempty(self._reqCreateOrderUniqueId) then
		GF.StartWait(10)
		return
	end
	GF.StopWait()
	local uniqueId = pb.uniqueId
	if uniqueId == self._reqCreateOrderUniqueId then
		self._reqCreateOrderUniqueId = nil
		--callback(CS.YXWebRet.ok,pb.orderId)
		gLSdkImpl:CallMethod(LSdkMethod.CreateOrderOk, {uniqueId = uniqueId, orderId = pb.orderId})
	end
end

function ModelPay:OnChargeResp(pb,ret)
	local money = pb.money
	if money >= 298 then
		LxUiHelper.PlayAudioSoundName(LSoundConst.TRIGGER_RECHARGE_LARGE)
	else
		LxUiHelper.PlayAudioSoundName(LSoundConst.TRIGGER_BUY_COMMON)
	end
	gLSdkImpl:CallMethod(LSdkMethod.CheckHasSceneEntryInfo,2)
end

function ModelPay:OnLockGoodsInfoResp(pb)
    self._lockedList = {}
	local priviTypeMap = {}
    for k,v in ipairs(pb.goodsInfo) do
        self._lockedList[v.productId] = {
            productId = v.productId,
            expire = v.expire,
			source = v.source
        }

		local has,priviType = self:GetPrivilegeType(v.productId)
		if has then
			local data = priviTypeMap[priviType]
			if not data then
				data =
				{
					type = priviType,
					expire = v.expire,
				}
				priviTypeMap[priviType] = data
			end

			local max = math.max(data.expire,v.expire)
			data.expire = max
		end
    end

	self._priviTypeLock = priviTypeMap
end

function ModelPay:OnSpecialChargeDataResp(pb)
	if pb.sid ~= self._sid then return end

	local voucherItem =  pb.voucherItem
	if string.isempty(voucherItem) then return end

	local voucherItemList = string.split(voucherItem, ':')
	local payId = voucherItemList[1]

	if not self:CheckNewSpecialChargePayId(payId) then
		return
	else
		gModelPay:SetNewSpecialChargePayId(payId)
	end

	local rewardList = voucherItemList[2]
	local reward = LxDataHelper.ParseItem(rewardList)
	local itemList = {}
	for k,v in ipairs(reward) do
		local tab = {
			itype = v.itemType,
			itemId = v.itemId,
			count = v.itemNum,
		}
		table.insert(itemList, tab)
	end

	local rebateThings =  pb.rebateThings
	if not string.isempty(rebateThings) then
		local reward2 = LxDataHelper.ParseItem(rebateThings)
		for k,v in ipairs(reward2) do
			local tab = {
				itype = v.itemType,
				itemId = v.itemId,
				count = v.itemNum,
			}
			table.insert(itemList, tab)
		end
	end

	local callBackFunc = function()
		--gModelPlayer:OnKKKAuthReceiveReq(5)
	end

	local tempWnd = {
		uiName = "UIAward",
		para = {
			itemList = itemList,
			callBackFunc = callBackFunc,
		}
	}
	gModelGeneral:InsertTimeLimitWndEx(tempWnd)
end

function ModelPay:SetNewSpecialChargePayId(payId)
	self._specialChargePayIdList[payId] = false
end

function ModelPay:CheckNewSpecialChargePayId(payId)
	local isNew = true
	for k,v in pairs(self._specialChargePayIdList) do
		if payId == k then
			isNew = v
			break
		end
	end

	return isNew
end

function ModelPay:ParseConfig()
	self._vipLvGiftList = {}
	self._typeVipGiftList = {}
	for k,v in pairs(GameTable.PremiumGiftRef) do
		local level,refId = v.level,v.refId
		local levelList = self._vipLvGiftList[level]
		if not levelList then
			levelList = {}
			self._vipLvGiftList[level] = levelList
		end
		levelList[refId] = v
		local vipType = v.type
		if vipType == 3 then
			self._typeVipGiftList[level] = v
		end
	end

	self._specialChargePayIdList = {}
	--printInfoNR("==============")
end

