function ModelPay:GetVipDescListByVipLv(VipLv)
	local ref  = {}
	for k,v in pairs(GameTable.PremiumPowerDesRef) do
		if v.level == VipLv and not string.isempty(ccLngText(v.des)) then
			table.insert(ref,v)
		end
	end
	table.sort(ref,function(t1,t2)
		local up1,up2 = t1.up,t2.up
		if up1 == up2 then
			local nowValue1,nowValue2 = t1.nowValue,t2.nowValue
			if nowValue1 == nowValue2 then
				return t1.sort > t2.sort
			end
			return nowValue1 > nowValue2
		end
		return up1 > up2
	end)
	return ref
end

-- giftType:1为礼包购买，2为充值
function ModelPay:PayCtrl(refId,giftType)
	if giftType == 1 then
		self:OnVipGiftBuyReq(refId)
	else
		self._selRefId = refId
		local ref = self:GetRechargeByRefId(refId)
		local welfareId = ref.welfareId
		self:GiftPayCtrl(refId,welfareId,ModelPay.PAY_TYPE_PAY)
	end
end

-- refId:个自表refId or 条目id，welfareId:礼包价格表refId,payType:购买类型,payGift:礼包id
-- sid:活动id,pageid:分页id,entryId:条目id
function ModelPay:GiftPayCtrl(refId,welfareId,payType,payGift,sid,pageid,isAuto, isFree,params)
	params = params or {}
	if not self:CheckTimeAllow() then
		return
	end

	--日服用sdk的年龄限制弹窗
	-- if self:CheckShowJapanBuyLimit() then
	-- 	return
	-- end

	local sendRefId
	local getDiamonds = 0
	local TASys = nil
	local TASysName = nil
	local TAReward = nil
	if(payType==ModelPay.PAY_TYPE_PAY)then
		sendRefId = string.format("%s|%s|%s",welfareId,payType,refId)
		local rechargeRef = self:GetRechargeByRefId(refId)

		local getDiamondsData = tostring(rechargeRef.getDiamonds) or ""
		if string.find(getDiamondsData, '=') then
			local getDiamondsItemData = LxDataHelper.ParseItem_4(getDiamondsData)
			getDiamonds = tonumber(getDiamondsItemData.itemNum)
		else
			getDiamonds = tonumber(getDiamondsData) or 0
		end

	elseif(payType==ModelPay.PAY_TYPE_GIFT)then
		if payGift == ModelPay.PAY_TIMEWARDROBE_SKIN and params.shopId then
			sendRefId = string.format("%s|%s|%s#%s#%s",welfareId,payType,payGift,params.shopId,refId)
		else
			sendRefId = string.format("%s|%s|%s#%s",welfareId,payType,payGift,refId)
		end
		TASys = payGift
	elseif(payType==ModelPay.PAY_TYPE_ACTIVITY)then
		local canBuy = gModelActivity:CheckCanBuy(sid,true)
		if not canBuy then
			return
		end
		sendRefId = string.format("%s|%s|%s#%s#%s",welfareId,payType,sid,pageid,refId)

		TASys = sid
		TASysName = gModelActivity:GetDefaultActivityName(sid)
		local entryCfg = gModelActivity:GetWebActivityEntryData(sid,pageid,refId)
		if entryCfg then
			TAReward = entryCfg.reward
		end
	elseif payType == ModelPay.PAY_TYPE_GOLD_TICKET then
		sendRefId = string.format("%s|%s|%s",welfareId,payType,refId)
	end

	local isLock = self:CheckIsLocked(sendRefId)
	if isLock then
		GF.ShowMessage(ccClientText(22900))
		return
	end

	if payType ~= ModelPay.PAY_TYPE_GOLD_TICKET and not isFree then
		if self:InSideBuy(welfareId,sendRefId) then
			return
		end
	end

	local welfareRef = self:GetWelfareRefByRefId(welfareId)
	local name = welfareRef.name
	local WelfareProductPayPointRef = self:GetWelfareProductPayPointRef(welfareRef.payPoint)
	local price = WelfareProductPayPointRef.rmbPayPoint

	---打点数据
	local data = {
		goodsId = welfareId,
		name = name,
		desc = sendRefId,
		type = payType,
		sys = TASys or "",
		sysName = TASysName or "",
		reward = TAReward or "",
		price = tonumber(price),
	}

	local tab = {
		goodsId = welfareId,
		orderType = payType,
		originRefId = refId,
		orderRefId = sendRefId,
		money = price,
		productName = name,
		payPointRefId = welfareRef.payPoint,
		diamonds = getDiamonds,
		priceType = isAuto and 2 or 0,
	}


    self:PayImpl(tab,data)
end

-- 活动特殊处理，购买的是整个活动，例如成长基金
function ModelPay:GiftPayCtrlSpecial(refId,welfareId,payType,sid)

	if not self:CheckTimeAllow() then
		return
	end

	local sendRefId
	local getDiamonds = 0
    if payType == ModelPay.PAY_TYPE_ACTIVITY then
        sendRefId = welfareId .. "|" .. payType .. "|" .. sid .. "#0#0"
    else
        printErrorN(string.format("wrong pay type %s",payType))
        return
    end

	local isLock = self:CheckIsLocked(sendRefId)
	if isLock then
		GF.ShowMessage(ccClientText(22900))
		return
	end

	if self:InSideBuy(welfareId,sendRefId) then
		return
	end

	local TASys = sid
	local TASysName = gModelActivity:GetDefaultActivityName(sid)
	local TAReward = nil


	local welfareRef = self:GetWelfareRefByRefId(welfareId)
	local ref = self:GetWelfareProductPayPointRef(welfareRef.payPoint)
	local name = welfareRef.name
	local price = ref.rmbPayPoint
	local tab = {
		orderType = payType,
		originRefId = refId,
		orderRefId = sendRefId,
		money = price,
		productName =name,
		payPointRefId = welfareRef.payPoint,
		diamonds = getDiamonds
	}

	local data = {
		goodsId = welfareId,
		name = name,
		desc = sendRefId,
		type = payType,
		sys = TASys or "",
		sysName = TASysName or "",
		reward = TAReward or "",
		price = tonumber(price),
	}

    self:PayImpl(tab,data)
end

function ModelPay:InSideBuy(welfareId,sendRefId)
	if self:IsPayMoneyBuy(welfareId,sendRefId) then
		return true
	end

	if self:IsGoldTicketBuy(welfareId,sendRefId) then
		return true
	end
end

---现金券
function ModelPay:IsPayMoneyBuy(welfareId,sendRefId)
	local num = gModelItem:GetNumByRefId(ModelItem.ITEM_PAYMONEY)--id写死，只有一种
	local money = self:GetMoneyItemNeed(welfareId)
	if money <= 0 or num < money then
		return
	end
	local welfareRef = self:GetWelfareRefByRefId(welfareId)
	local name = gModelItem:GetNameByRefId(ModelItem.ITEM_PAYMONEY)


	GF.OpenWndTop("UIOrdinTip",{
		refId=51801,
		para={money,name,welfareRef.name,num,name},
		func=function ()
			self:OnInsideShoppingReq(sendRefId)
		end
	})

	return true
end

---奥兹金券
function ModelPay:IsGoldTicketBuy(welfareId,sendRefId)
	local num = gModelItem:GetNumByRefId(ModelItem.ITEM_GOLD_TICKET)--id写死，只有一种
	local money = self:GetMoneyItemNeed(welfareId)
	if money <= 0 or num < money then
		return
	end

	--local welfareRef = self:GetWelfareRefByRefId(welfareId)
	local name = gModelItem:GetNameByRefId(ModelItem.ITEM_GOLD_TICKET)

	if self:CheckIsSegmentation() then
		money = self:GetSegmentationStr(money)
		num = self:GetSegmentationStr(num)
	end

	local args =
	{
		title = name,
		para = {money,name,num},
		callback = function()
			self:OnInsideShoppingReq(sendRefId)
		end
	}

	GF.OpenWnd("UISpItemBuy",args)

	return true
end

---商品兑换券
function ModelPay:IsPayCoinCertificateBuy(welfareId,sendRefId)
	local welfareRef = self:GetWelfareRefByRefId(welfareId)
	local payPoint   = welfareRef.payPoint

	local itemList = gModelItem:GetItemTypeListByType(ModelItem.Item_COIN_CERTIFICATE)
	local itemData
	for k,v in ipairs(itemList) do
		if tonumber(v:GetNum()) > 0 then
			local refId = v:GetRefId()
			local itemRef = gModelItem:GetRefByRefId(refId)
			if itemRef then
				local curWelfareId = tonumber(itemRef.typeDate)
				local curWelfareRef = self:GetWelfareRefByRefId(curWelfareId)
				local curPayPoint	= curWelfareRef.payPoint
				if curPayPoint == payPoint then
					itemData = v
					break
				end
			end
		end
	end

	if not itemData then
		return false
	end

	local refId = itemData:GetRefId()
	local name = gModelItem:GetNameByRefId(refId)
	local num  = gModelItem:GetNumByRefId(refId)
	GF.OpenWndTop("UIOrdinTip",{refId=51802,para={name,num,name},func=function ()
		self:OnFixVoucherExchangeReq(sendRefId, refId)
	end})
	return true
end

---防止重复点击
function ModelPay:CheckTimeAllow()
	local curTime = Time.unscaledTime
	if self._buyTimeRecord and curTime - self._buyTimeRecord < 0.3 then
		return
	end
	self._buyTimeRecord = curTime
	return true
end

--日本地区需要检测弹年龄限制
function ModelPay:CheckShowJapanBuyLimit()
	if not gLGameLanguage:IsJapanRegion() then
		return false
	end

	local ageIndex = tonumber(LPlayerPrefs.japanBuyLimitAgeIndex)
	if string.isempty(ageIndex) or ageIndex ~= 0 then
		return false
	end

	GF.OpenWnd("UIJaLiPop")
	return true
end

