function ModelPay:GetValueByWelfareId(welfareId)
	local welfareRef = self:GetWelfareRefByRefId(welfareId)
	if not welfareRef then
		printErrorN("GameTable.PurchaseActivitiesPriceRef[refId] is not find, refId = "..welfareId)
		return 0
	end

    return self:GetValueByPayPoint(welfareRef.payPoint)
end

function ModelPay:GetValueByPayPoint(payPoint)
    local ref = self:GetWelfareProductPayPointRef(payPoint)
    local moneyType = self:GetMoneyType()
    local refKey = self:GetPayPointKey(moneyType)
    if not refKey then
        printErrorN(string.format("货币类型错误 %s",moneyType))
        return 0
    end
    local value = ref[refKey]
    if not value then
        printErrorN(string.format("付费点不存在 %s",refKey))
        return 0
    end
    return tonumber(value)
end

function ModelPay:GetShowByWelfareId(welfareId)
	local value = self:GetValueByWelfareId(welfareId)
	local str = gLSdkImpl:CallMethod(LSdkMethod.GetPayFormatValue, value)
	if str then return str end

	local symbol = self:GetMoneySymbol()
	if self:CheckIsSegmentation() then
		value = self:GetSegmentationStr(value)
	end
	if self:CheckIsConvertSign() then
		return string.format("%s%s",value, symbol)
	else
		return string.format("%s%s", symbol, value)
	end
end

-- 千分位分割返回字符串
function ModelPay:GetSegmentationStr(value)
	local currStr
	local currNumberArr = string.split(tostring(value), ".")
	local firstArr = currNumberArr[1]
	local firstArrCnt = #firstArr
	local decimals = firstArrCnt / 3--取小数点前的数,有几个3
	local len = math.floor(decimals)
	if firstArrCnt % 3 == 0 then
		len = len - 1
	end
	currStr = tostring(firstArr)
	--currStr =string.reverse(currStr)
	for i = 1, len do
		local cutOut = (3 * i) + (i - 1)
		currStr = string.sub(currStr, 0, #currStr - cutOut) .. "," .. string.sub(currStr, -cutOut)--每3位数加","
	end
	if not string.isempty(currNumberArr[2]) then
		currStr = currStr .. "." .. currNumberArr[2]
	end
	return currStr
end

function ModelPay:CheckIsSegmentation()
