function ModelPay:GetMoneySymbol()
	--local symbol = gLSdkImpl:CallMethod(LSdkMethod.GetCurrencySymbol)
	local moneyType = self:GetMoneyType()
	local symbol = self:GetPayPointSymbol(moneyType)
	return symbol
end

function ModelPay:GetSymbolRef(moneyType)
	local symbolMap = self._symbolRefMap
	if not symbolMap then
		symbolMap = {}
		local ref = self:GetModelConfig(ModelPay.PurchaseProductPaySymbolRef)
		for k,v in pairs(ref) do
			symbolMap[v.type] = v
		end
		self._symbolRefMap = symbolMap
	end

	return symbolMap[moneyType]
end

function ModelPay:GetPayPointKey(moneyType)
	local ref  = self:GetSymbolRef(moneyType)
	if not ref then
		return "rmbPayPoint"
	end
	return ref.name
end

function ModelPay:GetPayPointSymbol(moneyType)
	local ref  = self:GetSymbolRef(moneyType)
	if not ref then
		return ""
	else
		return ref.symbol or ""
	end
end

function ModelPay:FormatValueShow(value)
	local str = gLSdkImpl:CallMethod(LSdkMethod.GetPayFormatValue, value)
	if str then
		return str
	end
	local symbol = self:GetMoneySymbol()
	return string.format("%s%s",symbol,value)
end

function ModelPay:GetMoneyItemNeed(welfareId)
	local welfareRef = self:GetWelfareRefByRefId(welfareId)
	local ref = self:GetWelfareProductPayPointRef(welfareRef.payPoint)
	local value = ref.rmbPayPoint
	return tonumber(value)
end


