function ModelPay:CheckIsLocked(sendRefId)
    if not self._lockedList then
        return false
    end

    local data = self._lockedList[sendRefId]
	if data and data.expire > GetTimestamp() then
		return true
	end

	local has,priviType = self:GetPrivilegeType(sendRefId)
	if has then
		local lockData = self._priviTypeLock[priviType]
		if lockData and lockData.expire > GetTimestamp() then
			return true
		end
	end

    return false
end

function ModelPay:ReleaseSdkPayLock(productId)
	if not self._lockedList then
		return
	end

	local data = self._lockedList[productId]
	if data and data.source == 1 then
		local pb = LProtoHelper.CreateProto(LProtoIds.LockGoodsInfoReq)
		pb.productId = productId
		SendMessage(pb,LProtoIds.LockGoodsInfoReq)
	end
end


function ModelPay:GetPrivilegeType(sendRefId)
	local s,e,cap1,cap2,cap3,cap4 = string.find(sendRefId,"(%d+)|(%d+)|(%d+)#(%d+)")
	if s and e then
		local payType = tonumber(cap2)
		local giftType = tonumber(cap3)
		local giftRefId = tonumber(cap4)
		if payType~= ModelPay.PAY_TYPE_GIFT then
			return
		end

		if giftType ~= ModelPay.PAY_GIFT_PRIVILEGE then
			return
		end
		local priviType = gModelNormalActivity:GetPrivilegeType(giftRefId)
		if priviType then
			return true,priviType
		end
	end

end

function ModelPay:GetPayType(expendType,expend2)
	local txt
	local showIconImg = false
	local iconImg
	if expendType == ModelPay.TYPE_BUY_FREE then
		txt = ccClientText(11913)
	elseif expendType == ModelPay.TYPE_BUY_ITEM then
		showIconImg = true
		local expend2Info =  string.split(expend2,"=")
		txt = expend2Info[3]
		iconImg = gModelItem:GetItemIconByRefId(tonumber(expend2Info[2]))
	elseif expendType == self.TYPE_BUY_RMB then
		--local rmb = gModelPay:GetRMBValueByWelfareId(tonumber(expend2))
		txt = gModelPay:GetShowByWelfareId(tonumber(expend2)) --string.replace(ccClientText(21718),rmb)
	end
	return txt,showIconImg, iconImg
end


